191	static void nms_sorted_bboxes(const std::vector<BBoxRect>& bboxes, std::vector<int>& picked, float nms_threshold)
192	{
193	    picked.clear();
194	
195	    const int n = bboxes.size();
196	
197	    std::vector<float> areas(n);
198	    for (int i = 0; i < n; i++)
199	    {
200	        const BBoxRect& r = bboxes[i];
201	
202	        float width = r.xmax - r.xmin;
203	        float height = r.ymax - r.ymin;
204	
205	        areas[i] = width * height;
206	    }
207	
208	    for (int i = 0; i < n; i++)
209	    {
210	        const BBoxRect& a = bboxes[i];
211	
212	        int keep = 1;
213	        for (int j = 0; j < (int)picked.size(); j++)
214	        {
215	            const BBoxRect& b = bboxes[picked[j]];
216	
217	            // intersection over union
218	            float inter_area = intersection_area(a, b);
219	            float union_area = areas[i] + areas[picked[j]] - inter_area;
220	//             float IoU = inter_area / union_area
221	            if (inter_area / union_area > nms_threshold)
222	                keep = 0;
223	        }
224	
225	        if (keep)
226	            picked.push_back(i);
227	    }
228	}
