235	#include <stdio.h>
236	int yolo3_detection_output_forward(const std::vector<ncnn::Mat>& bottom_blobs, std::vector<ncnn::Mat>& top_blobs)
237	{
238	    if (b_inited == false) { yolo3_detection_output_init_params(); b_inited = true; }
239	
240		// gather all box
241		std::vector<BBoxRect> all_bbox_rects;
242		std::vector<float> all_bbox_scores;
243	
244		for (size_t b = 0; b < bottom_blobs.size(); b++)
245		{
246			std::vector< std::vector<BBoxRect> > all_box_bbox_rects;
247			std::vector< std::vector<float> > all_box_bbox_scores;
248			all_box_bbox_rects.resize(num_box);
249			all_box_bbox_scores.resize(num_box);
250			const ncnn::Mat& bottom_top_blobs = bottom_blobs[b];
251	
252			int w = bottom_top_blobs.w;
253			int h = bottom_top_blobs.h;
254			int channels = bottom_top_blobs.c;
255			const int channels_per_box = channels / num_box;
256	
257			// anchor coord + box score + num_class
258			if (channels_per_box != 4 + 1 + num_class)
259		    {
260				return -1;
261			}
262			int mask_offset = b * num_box;
263			int net_w = (int)(anchors_scale[b] * w);
264			int net_h = (int)(anchors_scale[b] * h);
265	
266	#pragma omp parallel for num_threads(4)
267			for (int pp = 0; pp < num_box; pp++)
268			{
269				int p = pp * channels_per_box;
270				int biases_index = mask[pp + mask_offset];
271				const float bias_w = biases[biases_index * 2];
272				const float bias_h = biases[biases_index * 2 + 1];
273				const float* xptr = bottom_top_blobs.channel(p);
274				const float* yptr = bottom_top_blobs.channel(p + 1);
275				const float* wptr = bottom_top_blobs.channel(p + 2);
276				const float* hptr = bottom_top_blobs.channel(p + 3);
277	
278				const float* box_score_ptr = bottom_top_blobs.channel(p + 4);
279	
280				// softmax class scores
281				ncnn::Mat scores = bottom_top_blobs.channel_range(p + 5, num_class);
282				//softmax->forward_inplace(scores, opt);
283	
284				for (int i = 0; i < h; i++)
285				{
286					for (int j = 0; j < w; j++)
287					{
288						// region box
289						float bbox_cx = (j + sigmoid(xptr[0])) / w;
290						float bbox_cy = (i + sigmoid(yptr[0])) / h;
291						float bbox_w = exp(wptr[0]) * bias_w / net_w;
292						float bbox_h = exp(hptr[0]) * bias_h / net_h;
293	
294						float bbox_xmin = bbox_cx - bbox_w * 0.5f;
295						float bbox_ymin = bbox_cy - bbox_h * 0.5f;
296						float bbox_xmax = bbox_cx + bbox_w * 0.5f;
297						float bbox_ymax = bbox_cy + bbox_h * 0.5f;
298	
299						// box score
300						float box_score = sigmoid(box_score_ptr[0]);
301	
302						// find class index with max class score
303						int class_index = 0;
304						float class_score = 0.f;
305						for (int q = 0; q < num_class; q++)
306						{
307							float score = sigmoid(scores.channel(q).row(i)[j]);
308							if (score > class_score)
309							{
310								class_index = q;
311								class_score = score;
312							}
313						}
314	
315						float confidence = box_score * class_score;
316						if (confidence >= confidence_threshold)
317						{
318							BBoxRect c = { bbox_xmin, bbox_ymin, bbox_xmax, bbox_ymax, class_index };
319							all_box_bbox_rects[pp].push_back(c);
320							all_box_bbox_scores[pp].push_back(confidence);
321						}
322	
323						xptr++;
324						yptr++;
325						wptr++;
326						hptr++;
327	
328						box_score_ptr++;
329					}
330				}
331			}
332	
333			for (int i = 0; i < num_box; i++)
334			{
335				const std::vector<BBoxRect>& box_bbox_rects = all_box_bbox_rects[i];
336				const std::vector<float>& box_bbox_scores = all_box_bbox_scores[i];
337	
338				all_bbox_rects.insert(all_bbox_rects.end(), box_bbox_rects.begin(), box_bbox_rects.end());
339				all_bbox_scores.insert(all_bbox_scores.end(), box_bbox_scores.begin(), box_bbox_scores.end());
340			}
341	
342		}
343	
344	    // global sort inplace
345	    qsort_descent_inplace(all_bbox_rects, all_bbox_scores);
346	
347	    // apply nms
348	    std::vector<int> picked;
349	    nms_sorted_bboxes(all_bbox_rects, picked, nms_threshold);
350	
351	    // select
352	    std::vector<BBoxRect> bbox_rects;
353	    std::vector<float> bbox_scores;
354	
355	    for (int i = 0; i < (int)picked.size(); i++)
356	    {
357	        int z = picked[i];
358	        bbox_rects.push_back(all_bbox_rects[z]);
359	        bbox_scores.push_back(all_bbox_scores[z]);
360	    }
361	
362	    // fill result
363	    int num_detected = bbox_rects.size();
364		ncnn::Mat top_blob;
365		top_blob.create(6, num_detected, 1, 4u);
366	    if (top_blob.empty())
367	        return -100;
368	
369	    for (int i = 0; i < num_detected; i++)
370	    {
371	        const BBoxRect& r = bbox_rects[i];
372	        float score = bbox_scores[i];
373	        float* outptr = top_blob.row(i);
374	
375	        outptr[0] = r.label + 1;// +1 for prepend background class
376	        outptr[1] = score;
377	        outptr[2] = r.xmin;
378	        outptr[3] = r.ymin;
379	        outptr[4] = r.xmax;
380	        outptr[5] = r.ymax;
381	    }
382	    top_blobs.push_back(top_blob);
383	
384	    return 0;
385	}
